<script setup lang="ts">
import { computed, reactive } from 'vue'
import { useFullscreenElement } from '../lib/useFullscreen'
import { buildEnterpriseMixSensitivityRows, buildSsdShipmentSensitivityRows, calculateNandSsdDemand, formatCapacityTb, formatNumber, listNandSsdScenarioPresets, type NandSsdDemandInput } from '../lib/nandSsdDemand'
const input = reactive<NandSsdDemandInput>({ totalSsdShipmentsMillion: 300, segments: [{ id: 'client', label: 'Client SSD', sharePercent: 80, averageCapacityTb: 1 }, { id: 'enterprise', label: 'Enterprise SSD', sharePercent: 18, averageCapacityTb: 8 }, { id: 'ai-storage', label: 'AI/Data-center SSD', sharePercent: 2, averageCapacityTb: 16 }] })
const { targetRef: simulatorRoot, isFullscreen, toggleFullscreen } = useFullscreenElement()
const presets = listNandSsdScenarioPresets()
function applyPreset(presetInput: NandSsdDemandInput) { Object.assign(input, { ...presetInput, segments: presetInput.segments.map((segment) => ({ ...segment })) }) }
const result = computed(() => calculateNandSsdDemand(input))
const shipmentSensitivityRows = computed(() => buildSsdShipmentSensitivityRows(input, [-20, -10, 0, 10, 20]))
const enterpriseMixRows = computed(() => buildEnterpriseMixSensitivityRows(input, [10, 20, 30, 40, 50]))
const maxDemand = computed(() => Math.max(...enterpriseMixRows.value.map((row) => row.result.totalNandTb)))
const currentScenarioLabel = computed(() => presets.find((preset) => JSON.stringify(preset.input) === JSON.stringify({ ...input }))?.label ?? 'Custom user scenario')
</script>
<template><section ref="simulatorRoot" class="simulator-card" style="--sim-a:rgba(34,197,94,.10);--sim-b:rgba(14,165,233,.08)" :class="{ 'is-fullscreen': isFullscreen }"><div class="simulator-header"><div><p class="eyebrow">Assumption Workbench · NAND SSD</p><h2>NAND SSD 수요</h2></div><div><p class="formula">Demand = SSD Units × Segment Mix × TB/SSD</p><button class="simulator-fullscreen-toggle" type="button" @click="toggleFullscreen">{{ isFullscreen ? '전체화면 종료' : '전체화면' }}</button></div></div><div class="simulator-workbench"><div class="workbench-main"><div class="preset-comparison"><h3>Scenario presets</h3><table><thead><tr><th>Preset</th><th>Shipments</th><th>Avg TB/SSD</th><th>Confidence</th><th></th></tr></thead><tbody><tr v-for="preset in presets" :key="preset.id"><td><strong>{{ preset.label }}</strong><br/><small>{{ preset.description }}</small></td><td>{{ preset.input.totalSsdShipmentsMillion }}M</td><td>{{ formatNumber(calculateNandSsdDemand(preset.input).weightedAverageCapacityTb, 2) }} TB</td><td class="preset-source-row"><b class="confidence-badge">{{ preset.confidence }}</b> · {{ preset.sourceRefs.length }} refs</td><td><button class="apply-button" type="button" @click="applyPreset(preset.input)">Apply scenario</button></td></tr></tbody></table></div><div class="panel"><h3>Assumptions</h3><div class="control-grid"><article class="control-row"><label>SSD shipments <input v-model.number="input.totalSsdShipmentsMillion" type="number" min="0" step="5" /></label><input v-model.number="input.totalSsdShipmentsMillion" type="range" min="100" max="600" step="5" /><div class="quick-chips"><button class="quick-chip" @click="input.totalSsdShipmentsMillion = 250">250M</button><button class="quick-chip" @click="input.totalSsdShipmentsMillion = 300">300M</button><button class="quick-chip" @click="input.totalSsdShipmentsMillion = 400">400M</button></div><p class="impact">Impact: unit growth multiplies weighted capacity.</p><span class="source-pill">User input</span></article><article v-for="segment in input.segments" :key="segment.id" class="control-row"><label>{{ segment.label }} share <input v-model.number="segment.sharePercent" type="number" min="0" max="100" /></label><input v-model.number="segment.sharePercent" type="range" min="0" max="100" step="1" /><div class="quick-chips"><button class="quick-chip" @click="segment.sharePercent = 10">10%</button><button class="quick-chip" @click="segment.sharePercent = 25">25%</button><button class="quick-chip" @click="segment.sharePercent = 50">50%</button></div><label>TB/SSD <input v-model.number="segment.averageCapacityTb" type="number" min="0" step="0.5" /></label><input v-model.number="segment.averageCapacityTb" type="range" min="0.5" max="128" step="0.5" /><p class="impact">Impact: mix and content jointly drive weighted TB/SSD.</p><span class="source-pill">Source-backed capacity candidate</span></article></div></div><div class="sensitivity-bars"><h3>Visual sensitivity</h3><div v-for="row in enterpriseMixRows" :key="row.enterpriseSharePercent" class="bar-row"><span>{{ row.enterpriseSharePercent }}% enterprise</span><div class="bar-track"><div class="bar-fill" :style="{ width: `${(row.result.totalNandTb / maxDemand) * 100}%` }"></div></div><strong>{{ formatCapacityTb(row.result.totalNandTb) }}</strong></div><details class="table-wrap"><summary>Exact values</summary><table><tbody><tr v-for="row in shipmentSensitivityRows" :key="row.changePercent"><td>{{ row.changePercent }}% units</td><td>{{ formatCapacityTb(row.result.totalNandTb) }}</td></tr></tbody></table></details></div></div><aside class="result-rail"><div class="sticky-result-panel"><span class="primary-result-label">Primary result</span><strong class="primary-result-value">{{ formatNumber(result.totalNandEb, 2) }} EB</strong><p class="primary-result-note">{{ formatCapacityTb(result.totalNandTb) }} · {{ currentScenarioLabel }}</p><div class="result-grid"><article><span>Weighted TB/SSD</span><strong>{{ formatNumber(result.weightedAverageCapacityTb, 2) }} TB</strong></article><article><span>Normalized segments</span><strong>{{ result.normalizedSegments.map((s) => `${s.normalizedSharePercent}%`).join(' / ') }}</strong></article></div><p class="note">Shares normalize automatically when they do not sum to 100%.</p></div></aside></div></section></template>
